{{columns-start|num=4}}
Column 1 here
{{column}}
Column 2 here
{{column}}
Column 3 here
{{column}}
Column 4 here
{{columns-end}}
</syntaxhighlight>
{{column}}
<syntaxhighlight lang="wikitext">
{{columns-start|num=5}}
Column 1 here
{{column}}
Column 2 here
{{column}}
Column 3 here
{{column}}
Column 4 here
{{column}}
Column 5 here
{{columns-end}}
</syntaxhighlight>
{{columns-end}}

